final:
module RefModule (
        input [1:0] addr,
        input [3:0] data_in,
        input we,
        input clk,
        output reg [3:0] data_out);

    reg [3:0] mem [3:0];

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (we)
            mem[addr] <= data_in;
        data_out <= mem[addr];
    end

endmodule
